module RefModule(
    clk,
    in,
    load,
    address,
    out
 );input clk;             
    input [15:0] in;       
    input load;            
    input [15:0] address;  
    output [15:0] out;            

    reg [15:0] obf_ram[0:24000]; 
    reg [15:0]value; 

    always @(posedge clk ) begin
        if (load) begin
            obf_ram[address] <= in;
        end else begin
            value <= obf_ram[address];
        end
    end

    assign out = value;

endmodule
